1	/**
2	 * Persistent timeline that records each completed onboarding stage as a
3	 * `CompletedStageAccordion`. Renders between `MessagesRegion` and the active
4	 * stage panel; each accordion appears as its stage is acked and stays for
5	 * the rest of the flow so the user can scroll up and re-open any prior step.
6	 *
7	 * Order matches the linear stage queue: writing style → todos → workflows →
8	 * platforms. The accordions are independent — the active stage is responsible
9	 * for rendering its own in-progress UI.
10	 */
11	
12	"use client";
13	
14	import { Mail01Icon } from "@icons";
15	import { FIELD_NAMES } from "../constants";
16	import type { UseOnboardingChatReturn } from "../hooks/useOnboardingChat";
17	import type { OnboardingState } from "../state/types";
18	import { CompletedStageAccordion } from "./CompletedStageAccordion";
19	import { WritingStyleRevealCard } from "./reveal/WritingStyleRevealCard";
20	import { OnboardingChatStream } from "./stages/Chat";
21	
22	interface CompletedStagesTimelineProps {
23	  state: OnboardingState;
24	  chat: UseOnboardingChatReturn;
25	}
26	
27	export function CompletedStagesTimeline({
28	  state,
29	  chat,
30	}: CompletedStagesTimelineProps) {
31	  const writingStyle = state.server?.writing_style;
32	  const todos = state.server?.onboarding_todos ?? [];
33	  const workflows = state.server?.suggested_workflows ?? [];
34	
35	  const showWriting = state.ackedWritingStyle && !!writingStyle?.style_summary;
36	  const showTodos = state.ackedTodos && todos.length > 0;
37	  const showWorkflows = state.workflowsConfirmed && workflows.length > 0;
38	  const showPlatforms = state.platformsConfirmed;
39	
40	  if (!showWriting && !showTodos && !showWorkflows && !showPlatforms) {
41	    return null;
42	  }
43	
44	  return (
45	    <div className="mt-3 space-y-3">
46	      {showWriting && writingStyle?.style_summary && (
47	        <CompletedStageAccordion
48	          itemKey="writing-style"
49	          title="Writing style saved"
50	        >
51	          <WritingStyleRevealCard
52	            style_summary={writingStyle.style_summary}
53	            example={writingStyle.example ?? null}
54	            profession={state.responses[FIELD_NAMES.PROFESSION] ?? ""}
55	            embedded
56	          />
57	        </CompletedStageAccordion>
58	      )}
59	
60	      {showTodos && (
61	        <CompletedStageAccordion
62	          itemKey="todos"
63	          title={
64	            state.todoExecutionStarted && state.todoExecutionTodo
65	              ? `Ran "${state.todoExecutionTodo.title}"`
66	              : `Saved ${todos.length} ${todos.length === 1 ? "todo" : "todos"} for later`
67	          }
68	        >
69	          {state.todoExecutionStarted ? (
70	            <div className="space-y-4">
71	              <OnboardingChatStream
72	                chat={chat}
73	                todoOverride={state.todoExecutionTodo}
74	              />
75	            </div>
76	          ) : (
77	            <ul className="space-y-2">
78	              {todos.map((todo) => (
79	                <li
80	                  key={todo.id}
81	                  className="flex items-start gap-2 text-sm text-zinc-300"
82	                >
83	                  <span className="mt-1.5 size-1 shrink-0 rounded-full bg-zinc-500" />
84	                  <div className="min-w-0 flex-1">
85	                    <div className="text-zinc-200">{todo.title}</div>
86	                    {todo.source_email && (
87	                      <div className="mt-1 flex items-center gap-1.5 text-xs text-zinc-500">
88	                        <Mail01Icon className="size-3 shrink-0" />
89	                        <span className="truncate">
90	                          {todo.source_email.sender}
91	                        </span>
92	                      </div>
93	                    )}
94	                  </div>
95	                </li>
96	              ))}
97	            </ul>
98	          )}
99	        </CompletedStageAccordion>
100	      )}
101	
102	      {showWorkflows && (
103	        <CompletedStageAccordion
104	          itemKey="workflows"
105	          title={`${workflows.length} ${workflows.length === 1 ? "workflow" : "workflows"} added`}
106	        >
107	          <ul className="space-y-3">
108	            {workflows.map((wf, idx) => (
109	              <li key={wf.id ?? `${wf.title}-${idx}`} className="text-sm">
110	                <div className="font-medium text-zinc-200">{wf.title}</div>
111	                {wf.description && (
112	                  <div className="mt-0.5 text-xs text-zinc-400">
113	                    {wf.description}
114	                  </div>
115	                )}
116	              </li>
117	            ))}
118	          </ul>
119	        </CompletedStageAccordion>
